double Solution::new21Game(int n, int k, int maxPts) {
    if (k > n) return 1.0;
    if (k == n) return 1.0;
    double dp[n + 1];
    dp[0] = 1.0;
    double sum = 1.0;
    for (int i = 1; i <= n; i++) {
        if (i < k) dp[i] = sum / maxPts;
        else dp[i] = 1.0;
        if (i >= k - 1) sum -= dp[i - k + 1];
        if (i + 1 <= n) sum += dp[i + 1];
    }
    return dp[n];
}
